import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe('pull', () => {
  it('should handle object through-streams without throwing', () => {
    const source = (end: any, cb: Function) => {
      if (end) return cb(end)
      cb(null, 42)
    }

    let sinkRead: Function | null = null
    const throughObject = {
      sink: (read: Function) => {
        sinkRead = read
        throughObject.source = read
      },
      source: null as any
    }

    // In original code: object is handled by else-if branch (sink/source)
    // In mutated code: if(true) tries to call throughObject as a function, throwing TypeError
    expect(() => {
      pull(source, throughObject)
    }).not.toThrow()
  })
})
